#ifndef GQA_PAGED_PREFILL_CAUSAL_H32_KV4_D128_PS1_KERNEL_H_
#define GQA_PAGED_PREFILL_CAUSAL_H32_KV4_D128_PS1_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>
#include <torch/extension.h>

// Fixed constants from spec
constexpr int kNumQHeads  = 32;
constexpr int kNumKVHeads = 4;
constexpr int kHeadDim    = 128;
constexpr int kPageSize   = 1;
constexpr int kGQARatio   = kNumQHeads / kNumKVHeads; // 8
constexpr int kPageStrideElems = kPageSize * kNumKVHeads * kHeadDim; // 512 bf16 elems

void launch_gqa_paged_prefill_causal_h32_kv4_d128_ps1(
    const at::BFloat16* q,                // [total_q, 32, 128]
    const at::BFloat16* k_cache,          // [num_pages, 1, 4, 128]
    const at::BFloat16* v_cache,          // [num_pages, 1, 4, 128]
    const int32_t* qo_indptr,             // [len_indptr]
    const int32_t* kv_indptr,             // [len_indptr]
    const int32_t* kv_indices,            // [num_kv_indices]
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    at::BFloat16* output,                 // [total_q, 32, 128]
    float* lse,                           // [total_q, 32]
    cudaStream_t stream);

#endif // GQA_PAGED_PREFILL_CAUSAL_H32_KV4_D128_PS1_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>
#include <math_constants.h>

#ifndef CUDA_CHECK
#define CUDA_CHECK(expr) do {                                      \
  cudaError_t _err = (expr);                                       \
  if (_err != cudaSuccess) {                                       \
    printf("CUDA error %s at %s:%d\n", cudaGetErrorString(_err),    \
           __FILE__, __LINE__);                                    \
  }                                                                \
} while (0)
#endif

static __device__ __forceinline__ float ldg_bf16_to_f32(const at::BFloat16* p) {
  const __nv_bfloat16* pb = reinterpret_cast<const __nv_bfloat16*>(p);
#if __CUDA_ARCH__ >= 800
  __nv_bfloat16 v = __ldg(pb);
  return __bfloat162float(v);
#else
  return __bfloat162float(*pb);
#endif
}

static __device__ __forceinline__ void st_f32_to_bf16(at::BFloat16* p, float v) {
  __nv_bfloat16* pb = reinterpret_cast<__nv_bfloat16*>(p);
  *pb = __float2bfloat16_rn(v);
}

static __device__ __forceinline__ float warp_sum(float v) {
#pragma unroll
  for (int off = 16; off > 0; off >>= 1) v += __shfl_down_sync(0xffffffff, v, off);
  return v;
}

// Find b such that qo_indptr[b] <= tq < qo_indptr[b+1]. len_indptr = batch+1
static __device__ __forceinline__ int find_batch(const int32_t* __restrict__ qo_indptr,
                                                 int len_indptr, int tq) {
  int lo = 0, hi = len_indptr - 1;
  while (lo + 1 < hi) {
    int mid = (lo + hi) >> 1;
    int32_t v = __ldg(qo_indptr + mid);
    if (v <= tq) lo = mid;
    else hi = mid;
  }
  return lo;
}

// One block computes one (tq, qh). 128 threads map to d=128.
// Streaming softmax in base-2 to match reference lse = logsumexp(x)/log(2).
__global__ void gqa_paged_prefill_causal_h32_kv4_d128_ps1_kernel(
    const at::BFloat16* __restrict__ q,
    const at::BFloat16* __restrict__ k_cache,
    const at::BFloat16* __restrict__ v_cache,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    at::BFloat16* __restrict__ output,
    float* __restrict__ lse_out) {

  const int tq  = (int)blockIdx.x;
  const int qh  = (int)blockIdx.y;
  const int tid = (int)threadIdx.x; // 0..127

  if (tq >= total_q) return;

  const int b = find_batch(qo_indptr, (int)len_indptr, tq);

  const int32_t q_start  = __ldg(qo_indptr + b);
  const int32_t q_end    = __ldg(qo_indptr + b + 1);
  const int32_t kv_start = __ldg(kv_indptr + b);
  const int32_t kv_end   = __ldg(kv_indptr + b + 1);

  if (q_start >= q_end || kv_start >= kv_end) return;

  const int32_t num_q_tokens  = q_end - q_start;
  const int32_t num_kv_tokens = kv_end - kv_start;
  const int32_t q_local = (int32_t)tq - q_start;

  int32_t max_kv_idx = q_local + 1 + (num_kv_tokens - num_q_tokens);
  if (max_kv_idx > num_kv_tokens) max_kv_idx = num_kv_tokens;
  if (max_kv_idx <= 0) return;

  const int kvh = qh / kGQARatio;

  const int64_t q_base = ((int64_t)tq * kNumQHeads + qh) * kHeadDim;
  const int64_t o_base = q_base;

  const float qd = ldg_bf16_to_f32(q + q_base + tid);

  float m = -CUDART_INF_F; // max (in scaled logit domain)
  float s = 0.0f;          // sum exp2(logit-m)
  float od = 0.0f;         // weighted sum for this dim

  // Reduce dot(q,k) across 128 threads: 4 warps.
  __shared__ float sh_wsum[4];
  __shared__ float sh_logit;

  const int lane = tid & 31;
  const int warp = tid >> 5;

#pragma unroll 1
  for (int32_t j = 0; j < max_kv_idx; ++j) {
    const int32_t page_id = __ldg(kv_indices + (kv_start + j));
    const int64_t base = (int64_t)page_id * (int64_t)kPageStrideElems + (int64_t)kvh * kHeadDim;

    const float kd = ldg_bf16_to_f32(k_cache + base + tid);
    const float prod = qd * kd;

    float w = warp_sum(prod);
    if (lane == 0) sh_wsum[warp] = w;
    __syncthreads();

    if (warp == 0) {
      float x = (lane < 4) ? sh_wsum[lane] : 0.0f;
      float sum = warp_sum(x);
      if (lane == 0) sh_logit = sum * sm_scale;
    }
    __syncthreads();

    const float logit = sh_logit;

    const float m_new = fmaxf(m, logit);
    const float alpha = (m == -CUDART_INF_F) ? 0.0f : exp2f(m - m_new);
    const float beta  = exp2f(logit - m_new);

    const float vd = ldg_bf16_to_f32(v_cache + base + tid);

    od = od * alpha + vd * beta;
    s  = s  * alpha + beta;
    m  = m_new;

    __syncthreads();
  }

  const float outd = od / s;
  st_f32_to_bf16(output + o_base + tid, outd);

  if (tid == 0) {
    lse_out[(int64_t)tq * kNumQHeads + qh] = m + log2f(s);
  }
}

void launch_gqa_paged_prefill_causal_h32_kv4_d128_ps1(
    const at::BFloat16* q,
    const at::BFloat16* k_cache,
    const at::BFloat16* v_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    at::BFloat16* output,
    float* lse,
    cudaStream_t stream) {

  dim3 block(128, 1, 1);
  dim3 grid((unsigned)total_q, (unsigned)kNumQHeads, 1);

  gqa_paged_prefill_causal_h32_kv4_d128_ps1_kernel<<<grid, block, 0, stream>>>(
      q, k_cache, v_cache, qo_indptr, kv_indptr, kv_indices,
      len_indptr, total_q, sm_scale, output, lse);

  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <cmath>
#include <sstream>
#include <stdexcept>
#include <vector>

#include "kernel.h"

static void check(bool cond, const std::string& msg) {
  if (!cond) throw std::runtime_error(msg);
}

static void check_cuda(cudaError_t err, const char* where) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error at " << where << ": " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}

static torch::Tensor to_cuda_contig(torch::Tensor t,
                                   const torch::Device& dev,
                                   torch::Dtype dtype,
                                   const char* name) {
  check(t.defined(), std::string(name) + " must be defined");
  if (!t.device().is_cuda()) {
    t = t.to(dev, /*non_blocking=*/false, /*copy=*/true);
  } else {
    check(t.device() == dev, std::string(name) + " must be on the same CUDA device as q");
  }
  if (t.dtype() != dtype) t = t.to(dtype);
  if (!t.is_contiguous()) t = t.contiguous();
  return t;
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    c10::optional<double> sm_scale_opt = c10::nullopt) {

  check(q.defined(), "q must be defined");
  check(q.device().is_cuda(), "q must be a CUDA tensor");
  auto dev = q.device();

  q          = to_cuda_contig(q, dev, torch::kBFloat16, "q");
  k_cache    = to_cuda_contig(k_cache, dev, torch::kBFloat16, "k_cache");
  v_cache    = to_cuda_contig(v_cache, dev, torch::kBFloat16, "v_cache");
  qo_indptr  = to_cuda_contig(qo_indptr, dev, torch::kInt32, "qo_indptr");
  kv_indptr  = to_cuda_contig(kv_indptr, dev, torch::kInt32, "kv_indptr");
  kv_indices = to_cuda_contig(kv_indices, dev, torch::kInt32, "kv_indices");

  check(q.dim() == 3, "q must have shape [total_q, 32, 128]");
  check(q.size(1) == kNumQHeads, "q.shape[1] must be 32");
  check(q.size(2) == kHeadDim, "q.shape[2] must be 128");

  check(k_cache.dim() == 4, "k_cache must have shape [num_pages, 1, 4, 128]");
  check(v_cache.dim() == 4, "v_cache must have shape [num_pages, 1, 4, 128]");
  check(k_cache.size(1) == kPageSize, "k_cache.shape[1] must be 1");
  check(k_cache.size(2) == kNumKVHeads, "k_cache.shape[2] must be 4");
  check(k_cache.size(3) == kHeadDim, "k_cache.shape[3] must be 128");
  check(v_cache.sizes() == k_cache.sizes(), "v_cache must have same shape as k_cache");

  check(qo_indptr.dim() == 1, "qo_indptr must be 1D");
  check(kv_indptr.dim() == 1, "kv_indptr must be 1D");
  check(kv_indices.dim() == 1, "kv_indices must be 1D");

  const int64_t total_q64 = q.size(0);
  const int64_t len_indptr64 = qo_indptr.size(0);
  check(len_indptr64 == kv_indptr.size(0), "qo_indptr and kv_indptr must have same length");
  check(len_indptr64 >= 2, "indptr length must be >= 2");
  check(total_q64 <= INT32_MAX, "total_q too large");
  check(len_indptr64 <= INT32_MAX, "len_indptr too large");

  // Optional sanity: constraints from spec (best-effort, no sync)
  // total_q == qo_indptr[-1], num_kv_indices == kv_indptr[-1] (not enforced here to avoid sync)

  float sm_scale = sm_scale_opt.has_value()
      ? (float)(*sm_scale_opt)
      : (float)(1.0 / std::sqrt((double)kHeadDim));

  auto out = torch::zeros({total_q64, kNumQHeads, kHeadDim},
                          torch::TensorOptions().device(dev).dtype(torch::kBFloat16));
  auto lse = torch::full({total_q64, kNumQHeads}, -INFINITY,
                         torch::TensorOptions().device(dev).dtype(torch::kFloat32));

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  launch_gqa_paged_prefill_causal_h32_kv4_d128_ps1(
      (const at::BFloat16*)q.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)k_cache.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)v_cache.data_ptr<at::BFloat16>(),
      (const int32_t*)qo_indptr.data_ptr<int32_t>(),
      (const int32_t*)kv_indptr.data_ptr<int32_t>(),
      (const int32_t*)kv_indices.data_ptr<int32_t>(),
      (int32_t)len_indptr64,
      (int32_t)total_q64,
      sm_scale,
      (at::BFloat16*)out.data_ptr<at::BFloat16>(),
      (float*)lse.data_ptr<float>(),
      stream);

  // Key fix: do not call cudaDeviceSynchronize() in restricted sandboxes (can trigger pidfd_getfd issues).
  // Still surface launch/async errors as much as possible.
  check_cuda(cudaGetLastError(), "kernel launch");

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gqa_paged_prefill_causal_h32_kv4_d128_ps1 (CUDA)",
        py::arg("q"),
        py::arg("k_cache"),
        py::arg("v_cache"),
        py::arg("qo_indptr"),
        py::arg("kv_indptr"),
        py::arg("kv_indices"),
        py::arg("sm_scale") = py::none());
}
